import os
import json
from google.cloud import storage

class ModelLoader:
    def __init__(self):
        self.model_path = os.environ['MODEL_PATH']
        self.storage_client = storage.Client()

    def load_model(self):
        bucket_name, blob_name = self.model_path.split('/')
        bucket = self.storage_client.bucket(bucket_name)
        blob = bucket.blob(blob_name)
        model_json = json.loads(blob.download_as_string())
        return model_json